import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"Windows Nas","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/无线路由器/windowsnas.md","filePath":"ccc/无线路由器/windowsnas.md"}`),a={name:`ccc/无线路由器/windowsnas.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="windows-nas" tabindex="-1">Windows Nas <a class="header-anchor" href="#windows-nas" aria-label="Permalink to “Windows Nas”">​</a></h1><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to “参考链接”">​</a></h2><p><a href="https://www.chiphell.com/thread-1903476-1-1.html" target="_blank" rel="noreferrer">24盘位家庭虚拟化机架式服务器</a> ；<a href="https://koolshare.cn/forum.php?mod=viewthread&amp;tid=173537&amp;page=1&amp;extra=#pid2125701" target="_blank" rel="noreferrer">【大型终极版教程】ESXI+LEDE+DSM+WIN10</a></p><p>显卡解码支持：<a href="https://bluesky-soft.com/en/dxvac/deviceInfo/decoder/amd.html" target="_blank" rel="noreferrer">AMD GPU</a> <a href="https://bluesky-soft.com/en/dxvac/deviceInfo/decoder/intel.html" target="_blank" rel="noreferrer">Intel GPU</a> <a href="https://bluesky-soft.com/en/dxvac/deviceInfo/decoder/nvidia.html" target="_blank" rel="noreferrer">NVIDIA GPU</a></p><h2 id="windows能行么" tabindex="-1">windows能行么？ <a class="header-anchor" href="#windows能行么" aria-label="Permalink to “windows能行么？”">​</a></h2><p><a href="https://zhuanlan.zhihu.com/p/681227299" target="_blank" rel="noreferrer">D1581运行windows nas，hyper-v运行truenas记录。</a>+长江存储白片用于数据存储。</p><p>“实践是检验真理的唯一标准”，任何看似稳定的系统，无非是测试团队或用户踩过坑。windows占有率领先，反而认为其极不稳定，是完全没有道理的。</p><h3 id="其他系统" tabindex="-1">其他系统 <a class="header-anchor" href="#其他系统" aria-label="Permalink to “其他系统”">​</a></h3><p>1、OMV，PVE，TrueNas等，其实就是在debian基础上运行webui。</p><p>OMV尽量只通过webui调整设置，修改配置文件可能导致报错。</p><p>但凡需要跑win虚拟机，我会倾向于ESXi，或win主机。只要有win虚拟机运行，PVE主机就会积极睿频最大频率，功耗暴增。</p><p>2、群晖优势在于开箱即用，不需要折腾。smart出现异常会自动下线并报警。</p><blockquote><p>威联通要跑quts hero，能格式化成zfs的机型，才提供了擦洗（scrub）功能。</p></blockquote><p>3、斐讯n1等arm方案装armbian，这些方案的sata基本是usb转sata。nfs速度还行，samba速度很慢，在10mb/s到60mb/s之间波动。</p><h3 id="我为什么用windows" tabindex="-1">我为什么用windows <a class="header-anchor" href="#我为什么用windows" aria-label="Permalink to “我为什么用windows”">​</a></h3><ol><li><p>安卓模拟器有公司优化；linux下跑安卓没有公司优化适配国内手游，硬件开销大，挂机稳定性较差。</p></li><li><p>比特彗星多线程支持好，性能好很多；长效种子，ed2k插件死马当活马医。linux下除了transmission就是libtorrent，在国内更适合pt。</p></li></ol><blockquote><p>docker部署qbittorrent-EE，增加了对吸血迅雷的屏蔽，也可以考虑用于BT。</p></blockquote><ol start="3"><li>smb分享相对linux下的开源实现samba，cpu占用率低得多，速度也快，多线程优化好。相对linux下nfs分享，有更高的4k性能。</li></ol><blockquote><p>如果客户端是性能羸弱的安卓或linux设备，nfs分享能跑出更高的连续读写速度。</p></blockquote><ol start="4"><li>随便插张显卡搭配madvr直接做播放器。</li></ol><h2 id="文件系统" tabindex="-1">文件系统 <a class="header-anchor" href="#文件系统" aria-label="Permalink to “文件系统”">​</a></h2><p>机械硬盘raid并不适合家用，社群有大量讨论。</p><ul><li>bt下载数据我用snap raid。</li><li>其他文件我用hyper-v运行truenas搭配zfs镜像定期擦洗。</li></ul><h3 id="refs完整性流" tabindex="-1">ReFS完整性流 <a class="header-anchor" href="#refs完整性流" aria-label="Permalink to “ReFS完整性流”">​</a></h3><blockquote><p>ReFS还处于开发中，稳定性没有得到充分验证，<a href="https://chnhi.github.io/lxzdy/ccc/%E6%97%A0%E7%BA%BF%E8%B7%AF%E7%94%B1%E5%99%A8/%E9%BB%91%E7%BE%A4%E6%99%96zfs.html" target="_blank" rel="noreferrer">可以考虑Hyper-V运行TrueNAS+ZFS文件系统。</a></p></blockquote><p>ReFS可选功能，<a href="https://learn.microsoft.com/zh-cn/windows-server/storage/refs/integrity-streams" target="_blank" rel="noreferrer">完整性流，开启</a>后可以运行完整性清理器（linux叫擦洗scrub），校验文件好坏，避免固态硬盘的<a href="https://chnhi.github.io/lxzdy/ccc/%E6%97%A0%E7%BA%BF%E8%B7%AF%E7%94%B1%E5%99%A8/%E9%BB%91%E7%BE%A4%E6%99%96zfs.html#%E6%96%87%E4%BB%B6%E9%9D%99%E9%BB%98%E6%8D%9F%E5%9D%8F" target="_blank" rel="noreferrer">数据静默损坏</a>。</p><p>NTFS定期用7zip对整个磁盘计算CRC32也一样能实现固态硬盘的冷数据纠错预热，但毕竟没有校验。</p><blockquote><p>群晖使用LVM软RAID+魔改单盘BTRFS，群晖认为这样的方案足以商用。</p><p>那么windows存储空间-镜像+ReFS开启可选功能，完整性流可能也足够安全？</p></blockquote><blockquote><p>微软对完整性流的介绍中提到：ReFS 和存储空间可以共同自动地更正损坏的元数据和数据。</p><p>只有存储空间-镜像是可以搭配ReFS完整性校验并修复，镜像卷等不行。</p></blockquote><p>由于还在开发中，不同版本的windows使用的ReFS版本不同，被新版本系统升级过的ReFS，老版本是不能识别的。</p><p>存储空间一旦出现故障想要恢复非常麻烦，且需要手动回收空间。<a href="https://zhuanlan.zhihu.com/p/22604396" target="_blank" rel="noreferrer">Joe Chen：Win10和Win Server 2016存储池存储空间相关</a></p><h3 id="snap-raid" tabindex="-1">snap raid <a class="header-anchor" href="#snap-raid" aria-label="Permalink to “snap raid”">​</a></h3><p>类似于有校验的快照，就是修改文件不方便。</p><ol><li>硬盘容量可以不同，只要保证校验盘容量最大</li><li>随时加盘</li><li>就算坏了太多盘也不影响好盘的数据</li><li>成本低，不要阵列卡或者ecc</li><li>读写速度是单盘的速度，不需要读写整个阵列的硬盘</li></ol><p>缺点是每次修改了文件都必须要运行一下程序，以防万一可以把磁盘设置成只读。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>diskpart</span></span>
<span class="line"><span>list vol //列出磁盘</span></span>
<span class="line"><span>select vol 0 //选中要操作的盘</span></span>
<span class="line"><span>att vol set readonly  //设置只读</span></span>
<span class="line"><span></span></span>
<span class="line"><span>att vol clear readonly //清除只读</span></span></code></pre></div><h2 id="hyper-v" tabindex="-1">hyper-v <a class="header-anchor" href="#hyper-v" aria-label="Permalink to “hyper-v”">​</a></h2><p>优势是支持动态内存，主机关机的时候可以向虚拟机发送关机命令，而不是建立快照或强制关闭。</p><p>虚拟机出错偶尔只能强制重启主机。</p><p>主机一旦启用hyper-v，主机的网络流量也要走虚拟交换机，对延迟敏感的应用影响较大。</p><h4 id="hyper-v调度器" tabindex="-1">hyper-v调度器 <a class="header-anchor" href="#hyper-v调度器" aria-label="Permalink to “hyper-v调度器”">​</a></h4><p><a href="https://learn.microsoft.com/zh-cn/windows-server/virtualization/hyper-v/manage/manage-hyper-v-scheduler-types" target="_blank" rel="noreferrer">微软：管理调度器</a> ；<a href="https://learn.microsoft.com/zh-cn/windows-server/virtualization/hyper-v/manage/about-hyper-v-scheduler-type-selection?source=recommendations" target="_blank" rel="noreferrer">微软：调度器类型介绍</a></p><p>win10 1803之后的win10或11默认使用root调度器，虚拟机是主机下一个进程，任务管理器能看到，可以设置cpu相关性，开启超线程的情况下vcpu尽量设置至少4个，有可能调度到任意核心，运气不好2个vcpu调度到同一个物理核心，不过一般应该不会。总vcpu设置2倍逻辑核心数也没事。</p><p>server2016版本默认是classic，2019开始就是core。</p><p>classic下总vcpu设置2倍逻辑核心数也没事，core调度器分配给某个虚拟机的核心就不会再运行其他虚拟机的任务，开启超线程的情况下会通知虚拟机开启超线程，如果虚拟机系统禁用超线程，那么超线程出来的那个逻辑核心就会被闲置。</p><p>无论是clssic还是core，只能通过hyper-v管理器来管理cpu。</p><h4 id="半虚拟化" tabindex="-1"><strong>半虚拟化</strong> <a class="header-anchor" href="#半虚拟化" aria-label="Permalink to “半虚拟化”">​</a></h4><p>hyper-v运行linux虚拟机不用任何设置，一般默认就已经是&quot;半虚拟化&quot;。微软开发的Linux Integration Services，在linux上一般默认开启。但是性能比vmware的半虚拟化接口要差一点。</p><p><img src="https://s2.loli.net/2024/02/15/P8xKwejC6OI7bmA.png" alt="屏幕截图 2024-02-08 013911.png"></p><p>据我测试windows下两块RTL8125b互连，iperf3发送64iB小包，小包转发性能为9.85kpps，如果用hyper-v半虚拟化接口，恐怕小包转发性能最多也就9kpps左右了。</p><h3 id="hyper-v磁盘直通" tabindex="-1">hyper-v磁盘直通： <a class="header-anchor" href="#hyper-v磁盘直通" aria-label="Permalink to “hyper-v磁盘直通：”">​</a></h3><ul><li>RDM磁盘直通（Raw Device Mapping），整个物理磁盘可以由虚拟机格式化，但是磁盘控制器还是由host主机管理，既smart信息在host主机下读取。读写还是用的半虚拟化接口。</li><li>sata控制器或nvme控制器作为pci设备直通到虚拟机下，smart信息在虚拟机内读取。</li></ul><p>windows主机下监控smart信息可以用hdd sentinel软件。windows主机virtualbox一般只能用半虚拟化接口virtio，好像没有pci直通。</p><ul><li><p>hyper-v提供pci直通，<a href="https://github.com/chanket/DDA" target="_blank" rel="noreferrer">gui小工具</a>。</p></li><li><p><strong>windows下想要RDM磁盘直通，</strong>需要先在windows主机上的“磁盘管理”（win+q搜索磁盘管理）右键准备直通的磁盘，脱机，之后在vmware或hyper-v的虚拟磁盘设置中就可以直接选择该磁盘。</p></li></ul><h4 id="virtualbox需要命令行" tabindex="-1">virtualbox需要命令行： <a class="header-anchor" href="#virtualbox需要命令行" aria-label="Permalink to “virtualbox需要命令行：”">​</a></h4><p>查看要直通的硬盘的DeviceID：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>wmic diskdrive list brief</span></span>
<span class="line"><span>或：</span></span>
<span class="line"><span>&quot;C:\\Program Files\\Oracle\\VirtualBox\\VBoxManage.exe&quot; list hostdrives</span></span></code></pre></div><p>在windows主机上的“磁盘管理”（win+q搜索磁盘管理）右键准备直通的磁盘，脱机。</p><p>win+q搜索cmd，右键，管理员身份运行。根据上文查到的ID修改后文的-rawdisk</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&quot;C:\\Program Files\\Oracle\\VirtualBox\\VBoxManage.exe&quot; internalcommands createrawvmdk -filename &quot;D:\\是中国人就买长江存储.vmdk&quot; -rawdisk \\.\\PhysicalDrive0</span></span></code></pre></div><p>只需要在virtualbox磁盘配置中虚拟磁盘选择生成的vmdk文件就是直通该磁盘，控制器接口可以改成virtio，网络接口也可以改成virtio。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>--partitions 1,2 参数可以指定特定分区。</span></span>
<span class="line"><span>查看某个磁盘的分区号：</span></span>
<span class="line"><span>&quot;C:\\Program Files\\Oracle\\VirtualBox\\VBoxManage.exe&quot; internalcommands  listpartitions -rawdisk \\\\.\\PhysicalDrive0</span></span></code></pre></div><h3 id="hyper-v安装" tabindex="-1">hyper-v安装 <a class="header-anchor" href="#hyper-v安装" aria-label="Permalink to “hyper-v安装”">​</a></h3><p>启用hyper-v，win+q搜索“启用或关闭Windows功能”，启用Hyper-V即可。</p><p>默认就会生成虚拟交换机，默认是NAT，桥接需要在虚拟交换机管理器中新建一个“外部”交换机，虚拟机可以被路由器分配一个IP。</p><blockquote><p>主机网络流量也都是从虚拟交换机走，停用虚拟交换机会导致主机断网，要从Hyper-v管理器删除。</p></blockquote><p>虚拟机设置中默认会启用安全启动，我一般关闭。</p><p>虚拟机设置中-网络适配器，按加号列出的高级功能下默认是动态MAC，我一般启动一次虚拟机后改成静态mac。</p><p>自动停止操作我倾向于改为关闭来宾操作系统，既主机关机时会向虚拟机也发送关机信号。</p><h4 id="truenas" tabindex="-1"><strong>truenas</strong> <a class="header-anchor" href="#truenas" aria-label="Permalink to “truenas”">​</a></h4><p>hyper-v网卡设置桥接，关闭安全启动，网卡设置为静态mac，禁用检查点，自动停止操作改为关闭来宾操作系统。</p><p>scsi控制器中添加DVD驱动器，挂载truenas的安装iso文件。再添加两个硬盘驱动器，新建两个32g虚拟磁盘即可启动安装。最小16g。建两个虚拟磁盘，truenas安装时会自动建立zfs镜像池。</p><h2 id="windows-nas设置" tabindex="-1">windows nas设置 <a class="header-anchor" href="#windows-nas设置" aria-label="Permalink to “windows nas设置”">​</a></h2><p><strong>文件分享：</strong></p><ul><li>登录的账户有密码，其他设备查看文件的时候直接登录该账户。</li><li>设置-以太网，设置为专有网络。</li><li>右键要分享的文件，共享-共享，一路下一步</li></ul><p><strong>远程连接</strong></p><p>在设置中搜索远程桌面，开启。其他电脑运行mstsc即可启动远程桌面软件连接，单击显示选项后即可保存连接快捷方式。</p><p><strong>本地不登录直接启动</strong></p><p>运行netplwiz，取消勾选“要使用本计算机，用户必须输入用户名和密码(E)”确认后输入账户密码即可。</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>微软屎吃撑，新版本这个选项神秘消失，运行regedit后找到</span></span>
<span class="line"><span>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\PasswordLess\\Device</span></span>
<span class="line"><span>双击DevicePasswordLessBuildVersion改成0。</span></span></code></pre></div><h3 id="samba校验" tabindex="-1"><strong>samba校验</strong> <a class="header-anchor" href="#samba校验" aria-label="Permalink to “samba校验”">​</a></h3><p>samba开启加密可以避免网络波动引起文件损坏，手机应用往往支持的SMB版本较老，有可能打不开。</p><p><a href="https://link.zhihu.com/?target=https%3A//docs.microsoft.com/en-us/windows-server/storage/file-server/smb-security" target="_blank" rel="noreferrer">微软官方文档</a></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>管理员模式运行powershell：</span></span>
<span class="line"><span>在整个文件共享服务器当中开启加密</span></span>
<span class="line"><span>Set-SmbServerConfiguration –EncryptData $true</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对特定共享开启加密:</span></span>
<span class="line"><span>Set-SmbShare –Name &lt;sharename&gt; -EncryptData $true</span></span></code></pre></div><h4 id="文件操作后校验" tabindex="-1">文件操作后校验 <a class="header-anchor" href="#文件操作后校验" aria-label="Permalink to “文件操作后校验”">​</a></h4><p>文件操作尽可能使用fastcopy并开启每次文件操作后校验，或用teracopy软件，速度慢一点但与资源管理器的ui结合更好。</p><h4 id="samba文件分享聚合" tabindex="-1">samba文件分享聚合 <a class="header-anchor" href="#samba文件分享聚合" aria-label="Permalink to “samba文件分享聚合”">​</a></h4><p>多盘场景下，群晖等可以聚合多个目录在同一个smb子目录下，Windows：</p><ul><li>商业软件StableBit Drivepool实现类似JBOD</li><li>windows挂载磁盘到文件夹而不是分配盘符</li><li>创建链接，只要分享d:\\share文件夹</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>mklink /j  &quot;d:\\share\\e&quot; &quot;e:&quot;</span></span></code></pre></div><h2 id="硬链搭配刮削" tabindex="-1">硬链搭配刮削 <a class="header-anchor" href="#硬链搭配刮削" aria-label="Permalink to “硬链搭配刮削”">​</a></h2><p>下载到的资源偶尔会自带nfo，为了防止被刮削器修改后导致做种出现问题，用如下脚本把E:\\t下的文件夹和常见视频文件或字幕文件硬链到E:\\t2文件夹下。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@echo off</span></span>
<span class="line"><span>set workingDir=E:\\t</span></span>
<span class="line"><span>set link=E:\\t2</span></span>
<span class="line"><span>mkdir &quot;%link%&quot;</span></span>
<span class="line"><span>XCOPY /T &quot;%workingDir%&quot; &quot;%link%&quot;</span></span>
<span class="line"><span>setlocal enabledelayedexpansion</span></span>
<span class="line"><span>for /r &quot;%workingDir%&quot; %%i in (*.mkv,*.mp4,*.m2ts,*.clpi,*.mpls,*.rmvb,*.srt,*.ass,*.iso) do ( </span></span>
<span class="line"><span>set &quot;dirnoname=%%~dpi&quot;</span></span>
<span class="line"><span>echo next</span></span>
<span class="line"><span>echo !dirnoname!%%~nxi</span></span>
<span class="line"><span>mklink /h &quot;%link%!dirnoname:%workingDir%=!%%~nxi&quot; &quot;%%i&quot; </span></span>
<span class="line"><span>)</span></span></code></pre></div><p>mklink /j或/d指向文件的位置。而/h硬链是同一个文件出现在不同位置。软链不能用于刮削，硬链可以用于刮削。硬链缺点是只能链在同一个硬盘。</p><h2 id="primo-cache缓存" tabindex="-1">primo cache缓存 <a class="header-anchor" href="#primo-cache缓存" aria-label="Permalink to “primo cache缓存”">​</a></h2><p>威联通建议缓存至少达到10%，最好有20%。既10t硬盘至少1t缓存，最好2t，不然命中率会很低。</p><p><a href="https://link.zhihu.com/?target=https%3A//bbs.itzmx.com/thread-100953-1-1.html" target="_blank" rel="noreferrer">primo cache4.1</a>，只缓读不缓写，不开一级缓存（内存），bt软件本身就有缓存，做种24小时后，空闲内存基本都被windows用作缓存。</p><p>pt可能同时下载的人少，缓存命中率非常低，基本一直在10%以内。</p><p>bt做种2t，500g缓存。命中率在60%~90%之间波动，测试2天，上传量60多个g，用光缓存盘500g。用光后平均每天更新100g的缓存，但是每天上传量也就25g左右。</p><h2 id="防止自动更新后自动重启" tabindex="-1"><strong>防止自动更新后自动重启</strong> <a class="header-anchor" href="#防止自动更新后自动重启" aria-label="Permalink to “防止自动更新后自动重启”">​</a></h2><p>事件查看器中，重启原因代码：0x80020010。</p><p>微硬真的是无法无天，组策略也是摆设，设置了也白设置，除非<a href="https://bbs.pcbeta.com/viewthread-1913968-1-2.html" target="_blank" rel="noreferrer">停用windows更新服务。</a></p><p>如果不想停用windows更新，可以把自动重启的二进制文件删掉：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\Windows\\System32\\Tasks\\Microsoft\\Windows\\UpdateOrchestrator</span></span>
<span class="line"><span>Reboot_AC</span></span>
<span class="line"><span>Reboot_Battery</span></span>
<span class="line"><span>备份两个文件，新建两个同名文件夹，设置成只读。</span></span></code></pre></div><h2 id="windows无显卡启动" tabindex="-1">windows无显卡启动 <a class="header-anchor" href="#windows无显卡启动" aria-label="Permalink to “windows无显卡启动”">​</a></h2><ul><li>装AMYUNI发布的usb虚拟显示器驱动。</li></ul><p><a href="https://www.amyuni.com/forum/viewtopic.php?t=3030" target="_blank" rel="noreferrer">发布链接</a>，<a href="https://www.amyuni.com/downloads/usbmmidd_v2.zip" target="_blank" rel="noreferrer">下载链接</a>。</p><p>解压后管理员运行usbmmidd.bat。</p><p>想要添加更多虚拟显示器，管理员运行cmd：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>deviceinstaller64 enableidd 1</span></span></code></pre></div><ul><li>利用parsec的虚拟显示器驱动的<a href="https://github.com/nomi-san/parsec-vdd" target="_blank" rel="noreferrer"><strong>parsec-vdd</strong></a> 。</li></ul><h2 id="搭配ups停电关机" tabindex="-1">搭配ups停电关机 <a class="header-anchor" href="#搭配ups停电关机" aria-label="Permalink to “搭配ups停电关机”">​</a></h2><ul><li>APC ups有一个小工具apcupsd</li><li>APC bk650等型号可以用apcPCPE软件</li><li>UPS停电自动关机助手，ping路由器，不通就关机</li><li>脚本</li></ul><ol><li>APC bk650，山特TG-BOX，长的像超大号排插，apc这款有替换电池卖，两款都能控制nas。价格在500左右，续航可能就几十分钟。铅酸电池。</li><li>雷迪司H1000M是最便宜能控制nas的ups。铅酸电池。</li><li>绿巨能1000VA/600W，雷迪司D650/360W，这两款都是入门级产品，200以内就能买到，雷迪司这款用的锂电池，绿巨能用的铅酸电池。没有控制功能。</li><li>山克 3000VA 1800W，后备式续航最猛的一款，停电了也要nas接着运行就选这款。</li><li>有些产品用的12v电瓶，铅酸用个两年基本就要换了，可以买12v锂电瓶换上去，锂电瓶寿命长一些。正因为换电瓶就行，二手的便宜好货自己换电池也就几十块。</li><li>标称容量虽然很大，但是本身转换效率80%，电源转换效率可能也在80%再加上铅酸电池衰减很快，对他们的续航能力不要抱有太大的期望。注意铅酸电池长时间亏电会腐蚀铅板，导致报废。</li><li>后备式的ups通常在断电后有10ms的切换时间，输出通常是方波，而不是正弦波，方波不适合带电机，对于电脑通常没什么影响。除非电源主电容相对负载太小否则断电的10ms对于家用没什么影响，没有必要买在线式。</li><li>如果非要买在线式，注意在线式的噪音一般都会更大些，而且因为都是针对政企市场，一般对nas支持度不高。山克 SC1K最便宜大牌，华为UPS2000-A-1KTTS便宜大腕，apc山特这种大牌就不说了。</li></ol>`,114)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};